(window.webpackJsonp=window.webpackJsonp||[]).push([[62],{689:function(r,n){r.exports="\x3c!-- \r\ntitle: 01-常用符号\r\nsort: \r\n--\x3e \r\n# Dos常用符号\r\n\r\n## @    命令行回显\r\n\r\n- 屏蔽当前行的回显\r\n\r\n  ```powershell\r\n  @echo off\r\n  ```\r\n\r\n## \\>    重定向符\r\n\r\n> \\>    传递结果至后面\r\n> \r\n> \\>\\>    传递结果但不覆盖\r\n\r\n## |      管道命令符\r\n\r\n> |    将第一条命令的结果当作第二条命令的参数使用\r\n> \r\n> ||    第一条命令失败后执行下一条：\r\n\r\n  ```powershell\r\n  di || echo Enter_Error\r\n  ```\r\n\r\n## &    组合命令符\r\n\r\n> &\t\t\t从前向后执行\r\n>\r\n> &&\t\t命令失败后不向后执行\r\n> \r\n\r\n  ```powershell\r\ndir test && (rd /s/q test & echo rd_run)\t# 存在test则删除\r\n  ```\r\n\r\n## ,;    逗号与分号\r\n\r\n- ，    可当空格使用\r\n- ；    当命令相同时隔离不同目标\r\n\r\n## ()    代码块\r\n\r\n- （）中的代码被看作一个整体\r\n\r\n## %1    参数\r\n\r\n- 接收执行时输入的参数"}}]);